      message = `Event loop ล่าช้ามาก (${lagMs.toFixed(2)}ms)`;
    } else if (lagMs > 50) {
      status = 'degraded';
      message = `Event loop หน่วงเวลา (${lagMs.toFixed(2)}ms)`;
    }

    return {
      status,
      message,
      details: {
        lagMs: Math.round(lagMs * 100) / 100,
      },
    };
  }

