  domain: string;
  content: string;
  entities: string[];
  timestamp: string;
  confidence: number;
  raw?: unknown;
}

let factCounter = 0;
function nextFactId(domain: string): string {
  return `hot:${domain}:${++factCounter}`;
}

/**
