}

/**
 * Normalize calculator/datetime results into retrieval facts.
 */
export function normalizeDeterministicFact(
  domain: string,
  toolName: string,
  result: any,
  query: string
): RetrievalFact {
  const now = new Date().toISOString();
  return {
    id: nextFactId(domain),
    source: {
      id: `tool:${toolName}`,
      type: "tool",
      name: toolName,
      freshness: "live",
      timestamp: now,
      confidence: 1.0,
    },
    domain,
    content: typeof result === "string" ? result : String(result),
    entities: [],
    timestamp: now,
