      type: 'mdes-ollama',
      baseUrl: mdesBaseUrl,
      model: mdesModel,
      capabilities: ['thai-language', 'general-purpose', 'reasoning', 'code-generation', 'low-latency'],
      priority: 100,
      enabled: true,
      healthStatus: 'unknown',
    };
    this.providers.set(config.id, config);
