    return {
      model: chosenModel,
      reason,
      confidence,
      fallback: isPreferred ? undefined : chosenModel,
    };
  }

  async routeToMDES(text: string): Promise<RoutingDecision> {
    return this.route(text, MDES_OLLAMA_MODELS);
